<script setup lang="ts">defineProps<{modelValue:boolean;label?:string;tone?:'life'|'study'}>();defineEmits<{"update:modelValue":[boolean]}>()</script><template><label style="display:inline-flex;align-items:center;gap:9px"><button type="button" @click="$emit('update:modelValue',!modelValue)" :style="{width:'42px',height:'24px',border:0,borderRadius:'999px',padding:'3px',background:modelValue?(tone==='study'?'var(--xj-blue)':'var(--xj-green)'):'#CBD5E1',transition:'all .2s'}"><i :style="{display:'block',width:'18px',height:'18px',borderRadius:'50%',background:'#fff',transform:modelValue?'translateX(18px)':'translateX(0)',transition:'all .2s',boxShadow:'0 2px 5px rgba(0,0,0,.18)'}"></i></button><span style="font-size:13px">{{label}}</span></label></template>
